# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

import os
from flask import Flask, request, jsonify
from web3 import Web3
from eth_account.messages import encode_defunct
import jwt
import datetime
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your-secret-key-change-in-production')

w3 = Web3()

def verify_signature(message, signature, expected_address):
    try:
        message_hash = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(message_hash, signature=signature)
        return recovered_address.lower() == expected_address.lower()
    except Exception as e:
        print(f"Signature verification error: {e}")
        return False

def generate_token(address):
    payload = {
        'address': address.lower(),
        'exp': datetime.datetime.utcnow() + datetime.timedelta(hours=24),
        'iat': datetime.datetime.utcnow()
    }
    token = jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')
    return token

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        
        if not token:
            return jsonify({'error': 'Token is missing'}), 401
        
        if token.startswith('Bearer '):
            token = token[7:]
        
        try:
            data = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
            current_address = data['address']
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'error': 'Invalid token'}), 401
        
        return f(current_address, *args, **kwargs)
    
    return decorated

@app.route('/api/auth/nonce', methods=['POST'])
def get_nonce():
    data = request.get_json()
    
    if not data or 'address' not in data:
        return jsonify({'error': 'Address is required'}), 400
    
    address = data['address']
    
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    nonce = os.urandom(16).hex()
    message = f"Sign this message to authenticate with our Web3 service.\n\nNonce: {nonce}\nAddress: {address.lower()}"
    
    return jsonify({
        'nonce': nonce,
        'message': message
    }), 200

@app.route('/api/auth/verify', methods=['POST'])
def verify_and_authenticate():
    data = request.get_json()
    
    required_fields = ['address', 'message', 'signature']
    if not data or not all(field in data for field in required_fields):
        return jsonify({'error': 'Address, message, and signature are required'}), 400
    
    address = data['address']
    message = data['message']
    signature = data['signature']
    
    if not Web3.is_address(address):
        return jsonify({'error': 'Invalid Ethereum address'}), 400
    
    if verify_signature(message, signature, address):
        token = generate_token(address)
        return jsonify({
            'success': True,
            'token': token,
            'address': address.lower()
        }), 200
    else:
        return jsonify({'error': 'Invalid signature'}), 401

@app.route('/api/auth/validate', methods=['GET'])
@token_required
def validate_token(current_address):
    return jsonify({
        'valid': True,
        'address': current_address
    }), 200

@app.route('/api/protected/profile', methods=['GET'])
@token_required
def get_profile(current_address):
    return jsonify({
        'address': current_address,
        'message': 'This is a protected endpoint'
    }), 200

@app.route('/api/health', methods=['GET'])
def health_check():
    return jsonify({'status': 'healthy'}), 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)